mapper.select:
SELECT *
FROM venue_info info
WHERE id IN (SELECT m_venue.id FROM (SELECT MAX(id) AS id, venue_code FROM venue_info GROUP BY venue_code) AS
m_venue)



    AND info.id IN

        #{value}




    AND info.venue_name = #{vo.venueName}



    AND info.id = #{vo.id}



    AND info.status = #{vo.status}



    AND info.venue_code = #{vo.venueCode}




    AND info.venue_platform_name IN

        #{code}





    AND info.venue_code IN

        #{code}




    AND info.venue_type = #{vo.venueType}



    AND info.venue_join_type = #{vo.venueJoinType}



    AND info.updater = #{vo.creator}



    AND info.currency_code LIKE CONCAT('%', #{vo.currencyCode}, '%')



    AND info.proportion_type = #{vo.proportionType}



    AND info.status IN

        #{status}




    AND info.venue_currency_type = #{vo.venueCurrencyType}

ORDER BY info.created_time DESC

SELECT info.id, info.venue_code, info.venue_currency_type, info.currency_code, info.venue_type, info.venue_platform, info.venue_icon, info.pc_venue_icon, info.h5_venue_icon, info.api_url as apiUrl, info.bet_url as betUrl, info.game_url as gameUrl, site_c.middle_icon_i18n_code, site_c.venue_name, site_c.icon_i18n_code, site_c.pc_icon_i18n_code, site_c.h5_icon_i18n_code, site_c.pc_background_code, site_c.pc_logo_code, site_c.ht_icon_i18n_code, site_c.small_icon1_i18n_code, site_c.small_icon2_i18n_code, site_c.small_icon3_i18n_code, site_c.small_icon4_i18n_code, site_c.small_icon5_i18n_code, site_c.small_icon6_i18n_code, info.venue_join_type, s_v.valid_proportion, s_v.handling_fee as venueProportion, info.proportion_type, info.venue_platform_name, s_v.status, site_c.updated_time, site_c.created_time, site_c.venue_desc, s_v.remark, s_v.maintenance_start_time, s_v.maintenance_end_time, s_v.creator, s_v.updater FROM venue_info info INNER JOIN site_venue s_v ON s_v.venue_code = info.venue_code LEFT JOIN site_venue_config site_c ON site_c.venue_code = info.venue_code and site_c.site_code = #{vo.siteCode} where s_v.site_code = #{vo.siteCode} and info.id in (SELECT max(id) as id FROM venue_info GROUP BY venue_code )
AND info.id IN
#{value}
AND info.venue_name = #{vo.venueName}
AND info.id = #{vo.id}
AND s_v.status = #{vo.status}
AND info.venue_code = #{vo.venueCode}
AND info.venue_code IN
#{code}
AND info.venue_type = #{vo.venueType}
AND s_v.updater = #{vo.creator}
AND info.currency_code LIKE CONCAT('%', #{vo.currencyCode}, '%')
AND info.proportion_type = #{vo.proportionType}
AND info.status IN
#{status}
AND info.venue_join_type = #{vo.venueJoinType}
AND info.venue_currency_type = #{vo.venueCurrencyType}
ORDER BY info.created_time DESC
